INSERT INTO `SOFT_SKILL_TOPIC` VALUES (1,'this is a title','this is a descritpion','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"this is a \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"bjcu7\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"7htl9\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"9us8u\",\"text\":\"test for a soft skill\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":4,\"style\":\"fontfamily-Impact\"},{\"offset\":11,\"length\":4,\"style\":\"SUBSCRIPT\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"4vr55\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"9eifa\",\"text\":\"topic \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"3uvss\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"dlpdg\",\"text\":\"test 222222\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":5,\"length\":6,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-08 02:03:50',1,1),(2,'What are Solf Skill?','Why do we care about them?','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"What Are Soft Skills?\",\"type\":\"header-one\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"1dakk\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"brbbo\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"dtr2j\",\"text\":\"Soft skills are non-technical skills that relate to how you work. They include how you interact with colleagues, how you solve problems, and how you manage your work.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":166,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":166,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":166,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":166,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"6gk32\",\"text\":\"Learn what soft skills are, types and examples of soft skills, and ways to develop soft skills.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":95,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":95,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":95,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":95,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"3f8af\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"b633i\",\"text\":\"What Are Soft Skills?\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":21,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":21,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":21,\"style\":\"fontsize-1.5rem\"},{\"offset\":0,\"length\":21,\"style\":\"fontfamily-Publico, Georgia, serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"dbjkc\",\"text\":\"Soft skills relate to how you work. Soft skills include interpersonal (people) skills, communication skills, listening skills, time management, and empathy, among others. They are among the top skills employers seek in the candidates they hire, because soft skills are important for just about every job.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":304,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":304,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":304,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":304,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":56,\"length\":13,\"style\":\"color-rgb(36,111,200)\"},{\"offset\":109,\"length\":16,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":56,\"length\":13,\"key\":1},{\"offset\":109,\"length\":16,\"key\":2}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"7p3qa\",\"text\":\"Hiring managers typically look for job candidates with soft skills because they make someone more successful in the workplace.1 Someone can be excellent with technical, job-specific skills, but if they can\'t manage their time or work within a team, they may not be successful in the workplace.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":127,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":128,\"length\":40,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":169,\"length\":124,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":127,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":128,\"length\":40,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":169,\"length\":124,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":127,\"style\":\"fontsize-17\"},{\"offset\":128,\"length\":40,\"style\":\"fontsize-17\"},{\"offset\":169,\"length\":124,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":127,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":128,\"length\":40,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":169,\"length\":124,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":126,\"length\":1,\"style\":\"color-rgb(0,0,238)\"},{\"offset\":126,\"length\":1,\"style\":\"fontsize-12.75\"},{\"offset\":169,\"length\":19,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":169,\"length\":19,\"key\":3}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"cbr6t\",\"text\":\"Alternate names: Interpersonal skills, essential skills, noncognitive skills\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":76,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":76,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":76,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":76,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":15,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"6qjv3\",\"text\":\"How Soft Skills Work\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":20,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":20,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":20,\"style\":\"fontsize-1.5rem\"},{\"offset\":0,\"length\":20,\"style\":\"fontfamily-Publico, Georgia, serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"7ri9v\",\"text\":\"Soft skills are also important to the success of most employers. After all, nearly every job requires employees to engage with others in some way.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":146,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":146,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":146,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":146,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"24kg6\",\"text\":\"Another reason hiring managers and employers look for applicants with soft skills is that soft skills are transferable skills that can be used regardless of the person\'s job. This makes job candidates with soft skills very adaptable and flexible employees.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":256,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":256,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":256,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":256,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":106,\"length\":19,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":106,\"length\":19,\"key\":4}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"bvc8\",\"text\":\"Soft skills are particularly important in customer-based jobs. These employees are in direct contact with customers. It takes several soft skills to be able to listen to a customer and provide that customer with helpful and polite service.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":239,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":239,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":239,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":239,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"68mnn\",\"text\":\"Even if you\'re not in a client-facing role, you need to be able to get along with coworkers, managers, vendors, and other people you interact with at work.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":155,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":155,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":155,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":155,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"ba9de\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"cs919\",\"text\":\"Types of Soft Skills\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":20,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":20,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":20,\"style\":\"fontsize-1.5rem\"},{\"offset\":0,\"length\":20,\"style\":\"fontfamily-Publico, Georgia, serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"97di0\",\"text\":\"Soft skills include the personal attributes, personality traits, and communication abilities needed for success on the job. Soft skills characterize how a person interacts in his or her relationships with others.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":212,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":212,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":212,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":212,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":69,\"length\":23,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":69,\"length\":23,\"key\":5}],\"data\":{\"text-align\":\"start\"}},{\"key\":\"87f49\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"6uffi\",\"text\":\"Soft skills include:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":20,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":20,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":20,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":20,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":20,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"8h9ck\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5vplr\",\"text\":\"Adaptability \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":12,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":12,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":12,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":12,\"styl