"text\":\"Positivity \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":11,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":11,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":11,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":11,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"bt2r2\",\"text\":\"Time management \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":15,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":15,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":15,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":15,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":15,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":0,\"length\":15,\"key\":10}],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"71hqg\",\"text\":\"Motivation \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":11,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":11,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":11,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":11,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":11,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":0,\"length\":11,\"key\":11}],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"clt6s\",\"text\":\"Problem-solving \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":16,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":16,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":16,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":16,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":16,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":0,\"length\":16,\"key\":12}],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"ejivq\",\"text\":\"Critical thinking\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":17,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":17,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":17,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":17,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"63cd8\",\"text\":\"Conflict resolution\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":19,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":19,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":19,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":19,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":19,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":0,\"length\":19,\"key\":13}],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"824im\",\"text\":\"Negotiation\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":11,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":11,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":11,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":11,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"fdtb2\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"ckbdj\",\"text\":\"More Soft Skills: List of the top soft skills employers value.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":29,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":30,\"length\":15,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":46,\"length\":16,\"style\":\"color-rgb(34,34,34)\"},{\"offset\":0,\"length\":29,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":30,\"length\":15,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":46,\"length\":16,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":29,\"style\":\"fontsize-17\"},{\"offset\":30,\"length\":15,\"style\":\"fontsize-17\"},{\"offset\":46,\"length\":16,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":29,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":30,\"length\":15,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":46,\"length\":16,\"style\":\"fontfamily-Rubik, Arial, sans-serif\"},{\"offset\":0,\"length\":16,\"style\":\"BOLD\"},{\"offset\":30,\"length\":15,\"style\":\"color-rgb(36,111,200)\"}],\"entityRanges\":[{\"offset\":30,\"length\":15,\"key\":14}],\"data\":{\"text-align\":\"start\"}},{\"key\":\"9b6hb\",\"text\":\"\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"bs858\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"7t093\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.thebalancecareers.com/thmb/4-Gz9oA1YcxWU-5tRjS_o984Bhs=/672x0/filters:max_bytes(150000):strip_icc():format(webp)/what-are-soft-skills-2060852-Final-edit-30916950cf934d53a0474069a0b94c62.jpg\",\"height\":\"500px\",\"width\":\"auto\"}},\"1\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/interpersonal-skills-list-2063724\",\"title\":\"interpersonal\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/interpersonal-skills-list-2063724\",\"title\":\"interpersonal\",\"targetOption\":\"\"}}}},\"2\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/types-of-listening-skills-with-examples-2063759\",\"title\":\"listening skills\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/types-of-listening-skills-with-examples-2063759\",\"title\":\"listening skills\",\"targetOption\":\"\"}}}},\"3\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/what-are-job-specific-skills-2063755\",\"title\":\"job-specific skills\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/what-are-job-specific-skills-2063755\",\"title\":\"job-specific skills\",\"targetOption\":\"\"}}}},\"4\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/transferable-skills-list-525490\",\"title\":\"transferable skills\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/transferable-skills-list-525490\",\"title\":\"transferable skills\",\"targetOption\":\"\"}}}},\"5\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/communication-skills-list-2063779\",\"title\":\"communication abilities\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/communication-skills-list-2063779\",\"title\":\"communication abilities\",\"targetOption\":\"\"}}}},\"6\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/important-adaptability-skills-4768260\",\"title\":\"Adaptability\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/important-adaptability-skills-4768260\",\"title\":\"Adaptability\",\"targetOption\":\"\"}}}},\"7\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/communication-skills-list-2063737\",\"title\":\"Communication&nbsp;\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/communication-skills-list-2063737\",\"title\":\"Communication&nbsp;\",\"targetOption\":\"\"}}}},\"8\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/creative-thinking-definition-with-examples-2063744\",\"title\":\"Creative thinking\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/creative-thinking-definition-with-examples-2063744\",\"title\":\"Creative thinking\",\"targetOption\":\"\"}}}},\"9\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/list-of-teamwork-skills-2063773\",\"title\":\"Teamwork\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/list-of-teamwork-skills-2063773\",\"title\":\"Teamwork\",\"targetOption\":\"\"}}}},\"10\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/time-management-skills-2063776\",\"title\":\"Time management\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/time-management-skills-2063776\",\"title\":\"Time management\",\"targetOption\":\"\"}}}},\"11\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/motivational-skills-with-examples-2059691\",\"title\":\"Motivation&nbsp;\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/motivational-skills-with-examples-2059691\",\"title\":\"Motivation&nbsp;\",\"targetOption\":\"\"}}}},\"12\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/problem-solving-skills-with-examples-2063764\",\"title\":\"Problem-solving&nbsp;\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/problem-solving-skills-with-examples-2063764\",\"title\":\"Problem-solving&nbsp;\",\"targetOption\":\"\"}}}},\"13\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/conflict-resolutions-skills-2063739\",\"title\":\"Conflict resolution\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/conflict-resolutions-skills-2063739\",\"title\":\"Conflict resolution\",\"targetOption\":\"\"}}}},\"14\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/list-of-soft-skills-2063770\",\"title\":\"top soft skills\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.thebalancecareers.com/list-of-soft-skills-2063770\",\"title\":\"top soft skills\",\"targetOption\":\"\"}}}}}}','2022-05-31 02:32:55',1,2),(3,'The STAR Method','The Secret to Acing Your Next Job Interview','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"4tabk\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"5eiog\",\"text\":\"You’re in a job interview, and things are going well. You didn’t get lost on your way to the office, you made some friendly small talk with the hiring manager, and you’re nailing your answers to the questions you’re being asked.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":123,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":135,\"length\":93,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":0,\"length\":123,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":124,\"length\":10,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":135,\"length\":93,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":0,\"length\":123,\"style\":\"fontsize-17\"},{\"offset\":124,\"length\":10,\"style\":\"fontsize-17\"},{\"offset\":135,\"length\":93,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":123,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":124,\"length\":10,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":135,\"length\":93,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":124,\"length\":10,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":124,\"length\":10,\"style\":\"UNDERLINE\"}],\"entityRanges\":[{\"offset\":124,\"length\":10,\"key\":1}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"arj0u\",\"text\":\"Just when you start thinking you have this in the bag, you hear the interviewer say, “Tell me about a time when…”\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":86,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":112,\"length\":1,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":0,\"length\":113,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":0,\"length\":113,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":113,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":86,\"length\":26,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":86,\"length\":26,\"style\":\"UNDERLINE\"}],\"entityRanges\":[{\"offset\":86,\"length\":26,\"key\":2}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"5uu0\",\"text\":\"Your stomach drops. You rack your brain for something—anything!—you can use as an example. You grasp at straws and finally stumble your way through an anecdote that only sort of satisfies the prompt.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":169,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":170,\"length\":7,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":178,\"length\":21,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":0,\"length\":169,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":170,\"length\":7,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":178,\"length\":21,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":0,\"length\":169,\"style\":\"fontsize-17\"},{\"offset\":170,\"length\":7,\"style\":\"fontsize-17\"},{\"offset\":178,\"length\":21,\"style\":\"fontsize-17\"},{\"offset\":0,\"length\":169,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":170,\"length\":7,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":178,\"length\":21,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":54,\"length\":9,\"style\":\"ITALIC\"},{\"offset\":170,\"length\":7,\"style\":\"ITALIC\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"4rcbj\",\"text\":\"\\nFirst of all, take comfort in the fact that we’ve all been there. These types of interview questions are tough to answer. But, here’s the good news: There’s a strategy you can use to come up with way more impressive answers to these dreaded questions: the STAR interview method.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":1,\"length\":80,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":102,\"length\":177,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":1,\"length\":80,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":82,\"length\":19,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":102,\"length\":177,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":1,\"length\":80,\"style\":\"fontsize-17\"},{\"offset\":82,\"length\":19,\"style\":\"fontsize-17\"},{\"offset\":102,\"length\":177,\"style\":\"fontsize-17\"},{\"offset\":1,\"length\":80,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":82,\"length\":19,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":102,\"length\":177,\"style\":\"fontfamily-Georgia, Helvetica, sans-serif\"},{\"offset\":82,\"length\":19,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":82,\"length\":19,\"style\":\"UNDERLINE\"}],\"entityRanges\":[{\"offset\":82,\"length\":19,\"key\":3}],\"data\":{}},{\"key\":\"5if0h\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"66v7c\",\"text\":\"What Is the STAR Interview Method?\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":34,\"style\":\"color-rgb(51,51,51)\"},{\"offset\":0,\"length\":34,\"style\":\"bgcolor-rgb(247,247,247)\"},{\"offset\":0,\"length\":34,\"style\":\"fontsize-32\"},{\"offset\":0,\"length\":34,\"style\":\"fontfamily-Barlow Semi Condensed\\\", Helvetica, sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"fjluj\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"phnh\",\"text\":\"The STAR interview technique offers a straightforward format you can use to answer behavioral interview questions—those prompts that ask you to provide a real-life example of how you handled a certain kind of situation at work in the past.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":83,\"length\":30,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":83,\"length\":30,\"style\":\"bgcolor-transparent\"},{\"offset\":83,\"length\":30,\"style\":\"UNDERLINE\"}],\"entityRanges\":[{\"offset\":83,\"length\":30,\"key\":4}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"1ojfm\",\"text\":\"Don’t worry—these questions are easy to recognize. They often have telltale openings like:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"39alb\",\"text\":\"Tell me about a time when…\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"e1075\",\"text\":\"What do you do when…\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"c2rs8\",\"text\":\"Have you ever…\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"esskj\",\"text\":\"Give me an example of…\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"4df0s\",\"text\":\"Describe a…\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"besn8\",\"text\":\"Thinking of a fitting example for your response is just the beginning. Then you also need to share the details in a compelling and easy-to-understand way—without endless rambling.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"5so9r\",\"text\":\"That’s exactly what the STAR interview method enables you to do. “It’s helpful because it provides a simple framework for helping a candidate tell a meaningful story about a previous work experience,” says Al Dea, the founder of CareerSchooled and a career and leadership coach.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":229,\"length\":14,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":250,\"length\":27,\"style\":\"color-rgb(56,82,212)\"},{\"offset\":229,\"length\":14,\"style\":\"bgcolor-transparent\"},{\"offset\":250,\"length\":27,\"style\":\"bgcolor-transparent\"},{\"offset\":229,\"length\":14,\"style\":\"UNDERLINE\"},{\"offset\":250,\"length\":27,\"style\":\"UNDERLINE\"}],\"entityRanges\":[{\"offset\":229,\"length\":14,\"key\":5},{\"offset\":250,\"length\":27,\"key\":6}],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"50mbr\",\"text\":\"So, let’s break down that framework. STAR is an acronym that stands for:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"6t3ka\",\"text\":\"Situation: Set the scene and give the necessary details of your example.\\nTask: Describe what your responsibility was in that situation.\\nAction: Explain exactly what steps you took to address it.\\nResult: Share what outcomes your actions achieved.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"BOLD\"},{\"offset\":73,\"length\":1,\"style\":\"BOLD\"},{\"offset\":136,\"length\":1,\"style\":\"BOLD\"},{\"offset\":195,\"length\":1,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"35fku\",\"text\":\"By using these four components to shape your anecdote, it’s much easier to share a focused answer, providing the interviewer with “a digestible but compelling narrative of what a candidate did,” says Dea. “They can follow along, but also determine based on the answer how well that candidate might fit with the job.”\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"justify\"}},{\"key\":\"6g0af\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"4ktld\",\"text\":\"https://www.themuse.com/advice/star-interview-method\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"eaun7\",\"text\":\"\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"7rp3e\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://pilbox.themuse.com/image.png?filter=antialias&h=367&opt=1&pos=top-left&prog=1&q=keep&url=https%3A%2F%2Fcms-assets.themuse.com%2Fmedia%2Flead%2Ffee1fbcc-1a7a-4301-9f48-00ba91d1ead2.png%3Fv%3D3dcb6f2b134957d70bbf7c130cdde13f874d5aa3&w=750\",\"height\":\"500px\",\"width\":\"auto\",\"alignment\":\"none\"}},\"1\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/4-small-talk-tips-thatll-instantly-make-your-interviewer-like-you-more\",\"title\":\"small talk\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/4-small-talk-tips-thatll-instantly-make-your-interviewer-like-you-more\",\"title\":\"small talk\",\"targetOption\":\"\"}}}},\"2\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/how-to-answer-tell-me-about-a-time-when-interview-questions\",\"title\":\"Tell me about a time when…\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/how-to-answer-tell-me-about-a-time-when-interview-questions\",\"title\":\"Tell me about a time when…\",\"targetOption\":\"\"}}}},\"3\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/interview-questions-and-answers\",\"title\":\"interview questions\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/interview-questions-and-answers\",\"title\":\"interview questions\",\"targetOption\":\"\"}}}},\"4\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/30-behavioral-interview-questions-you-should-be-ready-to-answer\",\"title\":\"behavioral interview questions\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/advice/30-behavioral-interview-questions-you-should-be-ready-to-answer\",\"title\":\"behavioral interview questions\",\"targetOption\":\"\"}}}},\"5\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"http://careerschooled.com/\",\"title\":\"CareerSchooled\",\"targetOption\":\"_blank\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"http://careerschooled.com/\",\"title\":\"CareerSchooled\",\"targetOption\":\"_blank\"}}}},\"6\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/coaches/al-dea\",\"title\":\"career and leadership coach\",\"targetOption\":\"\",\"_map\":{\"type\":\"LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"url\":\"https://www.themuse.com/coaches/al-dea\",\"title\":\"career and leadership coach\",\"targetOption\":\"\"}}}}}}','2022-05-31 02:39:40',1,2),(4,'Software Engineer interviews','Everything you need to prepare','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"a1717\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"bhpkj\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"EMBEDDED_LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.techinterviewhandbook.org/software-engineering-interview-guide/\",\"height\":\"1000\",\"width\":\"2000\"}}}}','2022-05-31 02:47:19',1,2),(5,'Technical Interviewing 101','Ultimate Guide to Acing Your Tech Interview in 2022','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"31frv\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"6bt5m\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"EMBEDDED_LINK\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://learntocodewith.me/posts/technical-interview/\",\"height\":\"600\",\"width\":\"1000\"}}}}','2022-05-31 02:48:54',1,2);
