INSERT INTO `PROGRAMMING_TOPIC` (`title`, `description`, `topic_information`, `created_date`, `is_active`, `created_by`)
VALUES
	('code','code description','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"this is a \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"bjcu7\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"7htl9\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"9us8u\",\"text\":\"test for a soft skill\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":4,\"style\":\"fontfamily-Impact\"},{\"offset\":11,\"length\":4,\"style\":\"SUBSCRIPT\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"4vr55\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"9eifa\",\"text\":\"topic \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":5,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"3uvss\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"dlpdg\",\"text\":\"test 222222\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":5,\"length\":6,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-07 21:04:39',1,1),
	('Soft Skills?','A deeper understanding of soft skills','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"Why?\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":4,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c0h2e\",\"text\":\"Simply hiring the most experienced candidate may seem like the most logical and sensible decision; but there’s a lot more to what makes a good team member than qualifications and experience. Understanding the difference between soft and hard skills, and why soft skills are absolutely essential is vital in establishing a stronger, more efficient team.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":352,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":352,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":352,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"c0om3\",\"text\":\"As business continues to evolve at a rapid pace, and the traditional concept of the \'career\' shifts and reshapes, having transferrable skills that can be applied in any position and any industry is only becoming more important every day.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":237,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":237,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":237,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2e3ul\",\"text\":\"While for a long while, hard skills were considered the more \'professional skills\' and soft skills were viewed only as a CV space-filler, studies have shown that these days, human resources professionals tend to favour soft skills over hard skills when choosing the ideal candidate.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":282,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":282,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":282,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":138,\"length\":18,\"style\":\"color-inherit\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"9ht9g\",\"text\":\"Hard skills are measurable, tangible proficiencies that, while important in any position, are not the ultimate determinant of what makes a good employee. Hard skills refer to technical ability, like mathematics, reading comprehension, language fluency and computer skills, to name a few.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":287,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":287,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":287,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"s1jn\",\"text\":\"Soft skills, on the other hand, are personality traits and characteristics that are less quantifiable, but equally as important in the workplace and beyond, if not more. They’re rooted in behaviour, attitude and values.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":219,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":219,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":219,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"3s4j3\",\"text\":\"While hard skills have a larger impact on the work you produce, soft skills help develop human connections and establish a sense of culture and community in the workplace. Having said that, soft skills absolutely have a positive impact on the work you produce, especially when working collaboratively.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":301,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":301,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":301,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"f8pn1\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"eo2i6\",\"text\":\"What are the most important soft skills?\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":40,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":40,\"style\":\"fontsize-40\"},{\"offset\":0,\"length\":40,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":0,\"length\":40,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"426gm\",\"text\":\"1. Emotional intelligence\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":25,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":25,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":25,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"82h90\",\"text\":\"2. Communication\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":16,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":16,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":16,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7vrp3\",\"text\":\"3. Teamwork & respect\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":21,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":21,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":21,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c32u\",\"text\":\"4. Flexibility & creativity\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":27,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":27,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7h4rc\",\"text\":\"5. Problem-solving & critical thinking\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":38,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":38,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":38,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"62rl6\",\"text\":\"6. Leadership\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":13,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":13,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":13,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"med3\",\"text\":\"7. Time management & organisation\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":33,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":33,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":33,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"3592g\",\"text\":\"8. Motivation & work ethic\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":26,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":26,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":26,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"bnb2s\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"ef1o\",\"text\":\"Each one of these soft skills will be discussed more in depth in further activities.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":84,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":84,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":84,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"2mbgu\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"31d81\",\"text\":\"\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-29 19:29:43',1,1),
	('Trees','A parent and child data structure','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"Introduction\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":12,\"style\":\"BOLD\"},{\"offset\":0,\"length\":12,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":12,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"e5bbe\",\"text\":\"There are many basic data structures that can be used to solve application problems. Array is a good static data structure that can be accessed randomly and is fairly easy to implement. Linked Lists on the other hand is dynamic and is ideal for application that requires frequent operations such as add, delete, and update. One drawback of linked list is that data access is sequential. Then there are other specialized data structures like, stacks and queues that allows us to solve complicated problems : Maze traversal) using these restricted data structures. One other data structure is the hash table that allows users to program applications that require frequent search and updates. They can be done in O(1) in a hash table.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":712,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":713,\"length\":21,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":712,\"style\":\"fontsize-medium\"},{\"offset\":713,\"length\":21,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":734,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2ri8s\",\"text\":\"One of the disadvantages of using an array or linked list to store data is the time necessary to search for an item. Since both the arrays and Linked Lists are linear structures the time required to search a “linear” list is proportional to the size of the data set. For example, if the size of the data set is n, then the number of comparisons needed to find (or not find) an item may be as bad as some multiple of n. So imagine doing the search on a linked list (or array) with n = 106 nodes. Even on a machine that can do million comparisons per second, searching for m items will take roughly m seconds. This not acceptable in today’s world where speed at which we complete operations is extremely important. Time is money. Therefore it seems that better (more efficient) data structures are needed to store and search data.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":159,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":160,\"length\":17,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":178,\"length\":309,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":488,\"length\":340,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":159,\"style\":\"fontsize-medium\"},{\"offset\":160,\"length\":17,\"style\":\"fontsize-medium\"},{\"offset\":178,\"length\":309,\"style\":\"fontsize-medium\"},{\"offset\":488,\"length\":340,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":828,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":486,\"length\":1,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"40bud\",\"text\":\"In this chapter, we can extend the concept of linked data structure (linked list, stack, queue) to a structure that may have multiple relations among its nodes. Such a structure is called a tree. A tree is a collection of nodes connected by directed (or undirected) edges. A tree is a nonlinear data structure, compared to arrays, linked lists, stacks and queues which are linear data structures. A tree can be empty with no nodes or a tree is a structure consisting of one node called the root and zero or one or more subtrees. A tree has following general properties:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":88,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":89,\"length\":100,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":190,\"length\":94,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":285,\"length\":9,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":295,\"length\":194,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":490,\"length\":4,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":495,\"length\":23,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":519,\"length\":50,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":88,\"style\":\"fontsize-medium\"},{\"offset\":89,\"length\":100,\"style\":\"fontsize-medium\"},{\"offset\":190,\"length\":94,\"style\":\"fontsize-medium\"},{\"offset\":285,\"length\":9,\"style\":\"fontsize-medium\"},{\"offset\":295,\"length\":194,\"style\":\"fontsize-medium\"},{\"offset\":490,\"length\":4,\"style\":\"fontsize-medium\"},{\"offset\":495,\"length\":23,\"style\":\"fontsize-medium\"},{\"offset\":519,\"length\":50,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":569,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"6hngq\",\"text\":\"One node is distinguished as a root; \",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":30,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":31,\"length\":5,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":30,\"style\":\"fontsize-12pt\"},{\"offset\":31,\"length\":5,\"style\":\"fontsize-12pt\"},{\"offset\":0,\"length\":37,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0in\"}},{\"key\":\"f1khe\",\"text\":\"Every node (exclude a root) is connected by a directed edge from exactly one other node; A direction is: parent -> children\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":59,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":60,\"length\":4,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":65,\"length\":39,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":105,\"length\":18,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":59,\"style\":\"fontsize-12pt\"},{\"offset\":60,\"length\":4,\"style\":\"fontsize-12pt\"},{\"offset\":65,\"length\":39,\"style\":\"fontsize-12pt\"},{\"offset\":105,\"length\":18,\"style\":\"fontsize-12pt\"},{\"offset\":0,\"length\":123,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0in\"}},{\"key\":\"4o87i\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"42gl2\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"8ee6t\",\"text\":\"A is a parent of B, C, D, \\nB is called a child of A. \\non the other hand, B is a parent of E, F, K\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"color-red\"},{\"offset\":50,\"length\":1,\"style\":\"color-red\"},{\"offset\":73,\"length\":1,\"style\":\"color-red\"},{\"offset\":0,\"length\":1,\"style\":\"fontsize-16\"},{\"offset\":2,\"length\":14,\"style\":\"fontsize-16\"},{\"offset\":17,\"length\":8,\"style\":\"fontsize-16\"},{\"offset\":27,\"length\":1,\"style\":\"fontsize-16\"},{\"offset\":29,\"length\":20,\"style\":\"fontsize-16\"},{\"offset\":50,\"length\":2,\"style\":\"fontsize-16\"},{\"offset\":54,\"length\":18,\"style\":\"fontsize-16\"},{\"offset\":73,\"length\":1,\"style\":\"fontsize-16\"},{\"offset\":75,\"length\":14,\"style\":\"fontsize-16\"},{\"offset\":90,\"length\":7,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":97,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":2,\"length\":14,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":24,\"length\":1,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":29,\"length\":20,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":51,\"length\":1,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":54,\"length\":18,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":75,\"length\":14,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":17,\"length\":7,\"style\":\"color-blue\"},{\"offset\":27,\"length\":1,\"style\":\"color-blue\"},{\"offset\":90,\"length\":7,\"style\":\"color-blue\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"dkrqr\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"evoc3\",\"text\":\"A general tree\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":14,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":14,\"style\":\"BOLD\"},{\"offset\":0,\"length\":14,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":14,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"dvtdv\",\"text\":\"A general tree is a tree where each node may have zero or more children (a binary tree is a specialized case of a general tree). General trees are used to model applications such as file systems.  \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":197,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":197,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":197,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"9bdal\",\"text\":\" \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":1}],\"data\":{}},{\"key\":\"8oo2u\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":2}],\"data\":{}},{\"key\":\"8prh0\",\"text\":\"Implementation\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":14,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":14,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":14,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"cecnu\",\"text\":\"Since each node in a tree can have an arbitrary number of children, and that number is not known in advance, the general tree can be implemented using a first child/next sibling method. Each node will have TWO pointers: one to the leftmost child, and one to the rightmost sibling. The following picture illustrates this:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":112,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":113,\"length\":7,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":121,\"length\":31,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":153,\"length\":24,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":178,\"length\":27,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":206,\"length\":114,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":112,\"style\":\"fontsize-16\"},{\"offset\":113,\"length\":7,\"style\":\"fontsize-16\"},{\"offset\":121,\"length\":31,\"style\":\"fontsize-16\"},{\"offset\":153,\"length\":24,\"style\":\"fontsize-16\"},{\"offset\":178,\"length\":27,\"style\":\"fontsize-16\"},{\"offset\":206,\"length\":114,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":320,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"7sjt\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"88q8f\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":3}],\"data\":{}},{\"key\":\"455cq\",\"text\":\"The following Java code illustrates the implementation we have talked about here:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":81,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"8i27t\",\"text\":\"public class TNode {\\n      private Object  data;\\n      private MyLinkedList siblings;\\n      private TNode myLeftChild;\\n      public TNode(Object n){data=n; siblings=NULL;myLeftChild=NULL;}\\n}\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":190,\"style\":\"CODE\"},{\"offset\":0,\"length\":190,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"dioga\",\"text\":\"Binary Trees\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":12,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":12,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":12,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"hc2f\",\"text\":\"Binary trees are special trees that only have two children and every node has two pointers, one to the left child and another to the right child, these can be null if there is no node. A good implementation of this is shown here:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":229,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":229,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":229,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"elblm\",\"text\":\"public class BNode\\n{\\n   private Object data;\\n   private BNode left, right;\\n   public BNode()\\n   {\\n      data=left=right=null;\\n   }\\n   public BNode(Object data)\\n   {\\n      this.data=data;\\n      left=right=null;\\n   }\\n}\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":216,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":216,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":216,\"style\":\"CODE\"},{\"offset\":0,\"length\":216,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"5gud4\",\"text\":\"A binary tree in which each node has exactly zero or two children is called a full binary tree. In a full tree, there are no nodes with exactly one child. \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":75,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":76,\"length\":78,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":75,\"style\":\"fontsize-medium\"},{\"offset\":76,\"length\":78,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":155,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2r0ej\",\"text\":\"A complete binary tree is a tree, which is completely filled, with the possible exception of the bottom level, which is filled from left to right. A complete binary tree of the height h has between 2h and 2(h+1)-1 nodes. Here are some examples: \\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":22,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":23,\"length\":177,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":201,\"length\":43,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":22,\"style\":\"fontsize-medium\"},{\"offset\":23,\"length\":177,\"style\":\"fontsize-medium\"},{\"offset\":201,\"length\":43,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":246,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":199,\"length\":1,\"style\":\"SUPERSCRIPT\"},{\"offset\":206,\"length\":5,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5j6e9\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":4}],\"data\":{}},{\"key\":\"637af\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"fm04e\",\"text\":\"Full tree                                                Complete tree\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":70,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"fv24r\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"5r6md\",\"text\":\"Binary Search Trees\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":19,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":19,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":19,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"cpi2s\",\"text\":\"Given a binary tree, suppose we visit each node (recursively) as follows. We visit left child, then root and then the right child. For example, visiting the following tree\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":171,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":171,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":171,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"bcnaa\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"baiae\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":5}],\"data\":{}},{\"key\":\"a8n71\",\"text\":\"In the order defined above will produce the sequence {e, b,f,a,d,g} which we call flat(T). A binary search tree (BST) is a tree, where flat(T) is an ordered sequence. In other words, a binary search tree can be “searched” efficiently using this ordering property. A “balanced” binary search tree can be searched in O(log n) time, where n is the number of nodes in the tree.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":56,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":57,\"length\":77,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":135,\"length\":179,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":315,\"length\":58,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":56,\"style\":\"fontsize-medium\"},{\"offset\":57,\"length\":77,\"style\":\"fontsize-medium\"},{\"offset\":135,\"length\":179,\"style\":\"fontsize-medium\"},{\"offset\":315,\"length\":58,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":373,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"dckfq\",\"text\":\"In the next lesson we will learn some of the operations on BST’s.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":58,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":59,\"length\":6,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":58,\"style\":\"fontsize-medium\"},{\"offset\":59,\"length\":6,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":65,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7ocil\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image002.jpg\",\"height\":\"auto\",\"width\":\"auto\"}},\"1\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image004.jpg\",\"height\":\"auto\",\"width\":\"auto\"}},\"2\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image004.jpg\",\"height\":\"auto\",\"width\":\"auto\",\"alignment\":\"none\"}},\"3\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image006.jpg\",\"height\":\"auto\",\"width\":\"auto\"}},\"4\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image010.jpg\",\"height\":\"auto\",\"width\":\"auto\"}},\"5\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://www.cs.cmu.edu/~clo/www/CMU/DataStructures/Lessons/lesson4_1_files/image012.jpg\",\"height\":\"auto\",\"width\":\"auto\"}}}}','2022-05-30 09:03:50',1,1),
	('What is dynamic programming?','Those who don\'t know their past are destined to repeat it','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"Dynamic Programming is a technique in computer programming that helps to efficiently solve a class of problems that have overlapping subproblems and optimal substructure property.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":148,\"style\":\"fontsize-18\"},{\"offset\":149,\"length\":20,\"style\":\"fontsize-18\"},{\"offset\":170,\"length\":9,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":179,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":179,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7q41g\",\"text\":\"If any problem can be divided into subproblems, which in turn are divided into smaller subproblems, and if there are overlapping among these subproblems, then the solutions to these subproblems can be saved for future reference. In this way, efficiency of the CPU can be enhanced. This method of solving a solution is referred to as dynamic programming.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":353,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":353,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":353,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5h9f9\",\"text\":\"Such problems involve repeatedly calculating the value of the same subproblems to find the optimum solution.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":108,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":108,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":108,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"9haga\",\"text\":\"Let\'s find the fibonacci sequence upto 5th term. \\nA fibonacci series is the sequence of numbers in which each number is the sum of the two preceding ones. For example, 0, 1, 1, 2, 3. Here, each number is the sum of the two preceding numbers.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":241,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":241,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":241,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":40,\"length\":2,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"4rkk6\",\"text\":\"Algorithm\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":9,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":9,\"style\":\"BOLD\"},{\"offset\":0,\"length\":9,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":9,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"b90ej\",\"text\":\"Let n be the number of terms.\\n\\n1. If n <= 1, return 1.\\n2. Else, return the sum of two preceding numbers.\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":104,\"style\":\"fontsize-14\"},{\"offset\":0,\"length\":104,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":104,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":104,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"1mprp\",\"text\":\"We are calculating the fibonacci sequence up to the 5th term.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":61,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":61,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":61,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"199th\",\"text\":\"The first term is 0.\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":20,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":20,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":20,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":20,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"a9e97\",\"text\":\"The second term is 1.\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":21,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":21,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":21,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":21,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"3lrkf\",\"text\":\"The third term is sum of 0 (from step 1) and 1(from step 2), which is 1.\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":72,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":72,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":72,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":72,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"8qum6\",\"text\":\"The fourth term is the sum of the third term (from step 3) and second term (from step 2) i.e. 1 + 1 = 2.\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":93,\"style\":\"fontsize-16\"},{\"offset\":94,\"length\":10,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":93,\"style\":\"fontsize-18\"},{\"offset\":94,\"length\":10,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":104,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":104,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":94,\"length\":9,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"caheo\",\"text\":\"The fifth term is the sum of the fourth term (from step 4) and third term (from step 3) i.e. 2 + 1 = 3.\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":92,\"style\":\"fontsize-16\"},{\"offset\":93,\"length\":10,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":92,\"style\":\"fontsize-18\"},{\"offset\":93,\"length\":10,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":103,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":103,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":93,\"length\":9,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"3a343\",\"text\":\"Hence, we have the sequence 0, 1, 1, 2, 3. Here, we have used the results of the previous steps as shown below. This is called a dynamic programming approach.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"fontsize-18\"},{\"offset\":28,\"length\":100,\"style\":\"fontsize-18\"},{\"offset\":129,\"length\":29,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":158,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":158,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":28,\"length\":13,\"style\":\"CODE\"},{\"offset\":129,\"length\":28,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"eh9jk\",\"text\":\"F(0) = 0\\nF(1) = 1\\nF(2) = F(1) + F(0)\\nF(3) = F(2) + F(1)\\nF(4) = F(3) + F(2)\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":74,\"style\":\"fontsize-14\"},{\"offset\":0,\"length\":74,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":74,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":74,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"60p06\",\"text\":\"Dynamic Programming Methods\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":27,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":27,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"3ufj0\",\"text\":\"DP offers two methods to solve a problem.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":41,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":41,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":41,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":41,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"do5fs\",\"text\":\"Top-down with Memoization\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":25,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":25,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":25,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"50t1p\",\"text\":\"In this approach, we try to solve the bigger problem by recursively finding the solution to smaller sub-problems. Whenever we solve a sub-problem, we cache its result so that we don’t end up solving it repeatedly if it’s called multiple times. Instead, we can just return the saved result. This technique of storing the results of already solved subproblems is called Memoization.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":367,\"style\":\"fontsize-medium\"},{\"offset\":368,\"length\":12,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":367,\"style\":\"fontsize-18\"},{\"offset\":368,\"length\":12,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":380,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":380,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":368,\"length\":11,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"bgh16\",\"text\":\"We’ll see this technique in our example of Fibonacci numbers. First, let’s see the non-DP recursive solution for finding the nth Fibonacci number\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":145,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":145,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":145,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":145,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"diuj5\",\"text\":\"  public int CalculateFibonacci(int n) {\\n    if(n < 2)\\n      return n;\\n    return CalculateFibonacci(n-1) + CalculateFibonacci(n-2);\\n  }\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":136,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":136,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":136,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"fudhv\",\"text\":\"As we saw above, this problem shows the overlapping subproblems pattern, so let’s make use of memoization here. We can use an array to store the already solved subproblems.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":172,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":172,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":173,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":173,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}},{\"key\":\"avmd7\",\"text\":\"  public int CalculateFibonacci(int n) {\\n    int memoize[] = new int[n+1]; // this changed\\n    return CalculateFibonacciRecursive(memoize, n);\\n  }\\n\\n  public int CalculateFibonacciRecursive(int[] memoize, int n) {\\n    if(n < 2)\\n      return n;\\n\\n    // if we have already solved this subproblem, simply return the result from the cache\\n    if(memoize[n] != 0) // this changed\\n      return memoize[n]; // this changed\\n\\n    memoize[n] = CalculateFibonacciRecursive(memoize, n-1) + CalculateFibonacciRecursive(memoize, n-2);\\n    return memoize[n];\\n  }\\n\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":547,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":547,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":547,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"esuj7\",\"text\":\"Bottom-up with Tabulation\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":25,\"style\":\"fontsize-1.875rem\"},{\"offset\":0,\"length\":25,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":25,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"csd6g\",\"text\":\"Tabulation is the opposite of the top-down approach and avoids recursion. In this approach, we solve the problem “bottom-up” (i.e. by solving all the related sub-problems first). This is typically done by filling up an n-dimensional table. Based on the results in the table, the solution to the top/original problem is then computed.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":333,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":333,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":333,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c5ip0\",\"text\":\"Tabulation is the opposite of Memoization, as in Memoization we solve the problem and maintain a map of already solved sub-problems. In other words, in memoization, we do it top-down in the sense that we solve the top problem first (which typically recurses down to solve the sub-problems).\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":290,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":290,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":290,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"8oi9d\",\"text\":\"Let’s apply Tabulation to our example of Fibonacci numbers. Since we know that every Fibonacci number is the sum of the two preceding numbers, we can use this fact to populate our table.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":186,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":186,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":186,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"a65ob\",\"text\":\"Here is the code for our bottom-up dynamic programming approach:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":64,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":64,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":64,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5sc62\",\"text\":\"  public int CalculateFibonacci(int n) {\\n    if (n==0) return 0;\\n    int dp[] = new int[n+1];\\n\\n    //base cases\\n    dp[0] = 0;\\n    dp[1] = 1;\\n\\n    for(int i=2; i<=n; i++)\\n      dp[i] = dp[i-1] + dp[i-2];\\n\\n    return dp[n];\\n  }\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":226,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":226,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":226,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"4nsab\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"left\"}}],\"entityMap\":{}}','2022-05-30 20:56:13',1,1),
	('Dynamic Programming extras','More information on DP','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"How Dynamic Programming Works\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":29,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":29,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":29,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"1pp41\",\"text\":\"Dynamic programming works by storing the result of subproblems so that when their solutions are required, they are at hand and we do not need to recalculate them.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":162,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":162,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":162,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"egd66\",\"text\":\"This technique of storing the value of subproblems is called memoization. By saving the values in the array, we save time for computations of sub-problems we have already come across.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":183,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":183,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":183,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2rhqd\",\"text\":\"var m = map(0 → 0, 1 → 1)\\nfunction fib(n)\\n    if key n is not in map m \\n        m[n] = fib(n − 1) + fib(n − 2)\\n    return m[n]\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":126,\"style\":\"fontsize-14\"},{\"offset\":0,\"length\":126,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":126,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":126,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"fqkc0\",\"text\":\"Dynamic programming by memoization is a top-down approach to dynamic programming. By reversing the direction in which the algorithm works i.e. by starting from the base case and working towards the solution, we can also implement dynamic programming in a bottom-up manner.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":272,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":272,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":272,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"ijbv\",\"text\":\"function fib(n)\\n    if n = 0\\n        return 0\\n    else\\n        var prevFib = 0, currFib = 1\\n        repeat n − 1 times\\n            var newFib = prevFib + currFib\\n            prevFib = currFib\\n            currFib  = newFib\\n    return currentFib\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":243,\"style\":\"fontsize-14\"},{\"offset\":0,\"length\":243,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":243,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":243,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"ccbt1\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"cee62\",\"text\":\"Recursion vs Dynamic Programming\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":32,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":32,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":32,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"701s9\",\"text\":\"Dynamic programming is mostly applied to recursive algorithms. This is not a coincidence, most optimization problems require recursion and dynamic programming is used for optimization.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":184,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":184,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":184,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"21i5a\",\"text\":\"But not all problems that use recursion can use Dynamic Programming. Unless there is a presence of overlapping subproblems like in the fibonacci sequence problem, a recursion can only reach the solution using a divide and conquer approach.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":239,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":239,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":239,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"69e7s\",\"text\":\"That is the reason why a recursive algorithm like Merge Sort cannot use Dynamic Programming, because the subproblems are not overlapping in any way.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":148,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":149,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":149,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5369i\",\"text\":\"Greedy Algorithms vs Dynamic Programming\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":40,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":40,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":40,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"f360l\",\"text\":\"Greedy Algorithms are similar to dynamic programming in the sense that they are both tools for optimization.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":17,\"style\":\"fontsize-18\"},{\"offset\":18,\"length\":90,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":108,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":108,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"a9i51\",\"text\":\"However, greedy algorithms look for locally optimum solutions or in other words, a greedy choice, in the hopes of finding a global optimum. Hence greedy algorithms can make a guess that looks optimum at the time but becomes costly down the line and do not guarantee a globally optimum.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":285,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":285,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":285,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5jois\",\"text\":\"Dynamic programming, on the other hand, finds the optimal solution to subproblems and then makes an informed choice to combine the results of those subproblems to find the most optimum solution.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":194,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":194,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":0,\"length\":194,\"style\":\"color-rgb(0,0,0)\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"57jt8\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"t9ij\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"1t1n1\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-30 21:24:27',1,1),
	('Heaps','Sorted structures with minimal retrieval complexity','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"Heap data structure is a complete binary tree that satisfies the heap property, where any given node is\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":22,\"style\":\"fontsize-18\"},{\"offset\":23,\"length\":22,\"style\":\"fontsize-18\"},{\"offset\":46,\"length\":14,\"style\":\"fontsize-18\"},{\"offset\":61,\"length\":42,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":103,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":61,\"length\":17,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7tthc\",\"text\":\"always greater than its child node/s and the key of the root node is the largest among all other nodes. This property is also called max heap property.\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":132,\"style\":\"fontsize-16\"},{\"offset\":133,\"length\":18,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":132,\"style\":\"fontsize-18\"},{\"offset\":133,\"length\":18,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":151,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":133,\"length\":17,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"ctbit\",\"text\":\"always smaller than the child node/s and the key of the root node is the smallest among all other nodes. This property is also called min heap property.\",\"type\":\"unordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":133,\"style\":\"fontsize-16\"},{\"offset\":134,\"length\":18,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":133,\"style\":\"fontsize-18\"},{\"offset\":134,\"length\":18,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":152,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":134,\"length\":17,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"e4k1u\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"as3la\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":0}],\"data\":{}},{\"key\":\"fekkl\",\"text\":\"Max - Heap\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":10,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"374sv\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":1}],\"data\":{}},{\"key\":\"2c6rb\",\"text\":\"Min - Heap\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":10,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"9shco\",\"text\":\"This type of data structure is also called a binary heap.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":57,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"17gpv\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"a4tbe\",\"text\":\"Heap Operations\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":15,\"style\":\"fontsize-24\"},{\"offset\":0,\"length\":15,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"4uh4m\",\"text\":\"Some of the important operations performed on a heap are described below along with their algorithms.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":101,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":101,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"cthig\",\"text\":\"Heapify\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":7,\"style\":\"fontsize-20\"},{\"offset\":0,\"length\":7,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"do9p0\",\"text\":\"Heapify is the process of creating a heap data structure from a binary tree. It is used to create a Min-Heap or a Max-Heap.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":123,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":123,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5ajjm\",\"text\":\"Let the input array be:\",\"type\":\"ordered-list-item\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":23,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":23,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":23,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"6qo21\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":2}],\"data\":{}},{\"key\":\"7it5t\",\"text\":\"2. Create a complete binary tree from the array:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":48,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":0,\"length\":48,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":48,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"dhvan\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"5rigd\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":3}],\"data\":{}},{\"key\":\"ed7lo\",\"text\":\"3. Start from the first index of non-leaf node whose index is given by n/2 - 1\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":78,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":3,\"length\":67,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":3,\"length\":67,\"style\":\"fontsize-18\"},{\"offset\":71,\"length\":7,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"cisab\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"1msb3\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":4}],\"data\":{}},{\"key\":\"3hq4c\",\"text\":\"4. Set current element i as largest.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":36,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":3,\"length\":19,\"style\":\"fontsize-16\"},{\"offset\":23,\"length\":1,\"style\":\"fontsize-16\"},{\"offset\":25,\"length\":2,\"style\":\"fontsize-16\"},{\"offset\":28,\"length\":8,\"style\":\"fontsize-16\"},{\"offset\":3,\"length\":19,\"style\":\"fontsize-18\"},{\"offset\":23,\"length\":1,\"style\":\"fontsize-18\"},{\"offset\":25,\"length\":2,\"style\":\"fontsize-18\"},{\"offset\":28,\"length\":8,\"style\":\"fontsize-18\"},{\"offset\":23,\"length\":1,\"style\":\"CODE\"},{\"offset\":28,\"length\":7,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"dqfem\",\"text\":\"5. The index of left child is given by 2i + 1 and the right child is given by 2i + 2.\\nIf leftChild is greater than currentElement (i.e. element at ith index), set leftChildIndex as largest.\\nIf rightChild is greater than element in largest, set rightChildIndex as largest\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":3,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":38,\"style\":\"fontsize-18\"},{\"offset\":46,\"length\":31,\"style\":\"fontsize-18\"},{\"offset\":84,\"length\":1,\"style\":\"fontsize-18\"},{\"offset\":86,\"length\":2,\"style\":\"fontsize-18\"},{\"offset\":99,\"length\":15,\"style\":\"fontsize-18\"},{\"offset\":130,\"length\":16,\"style\":\"fontsize-18\"},{\"offset\":151,\"length\":11,\"style\":\"fontsize-18\"},{\"offset\":178,\"length\":11,\"style\":\"fontsize-18\"},{\"offset\":190,\"length\":2,\"style\":\"fontsize-18\"},{\"offset\":204,\"length\":26,\"style\":\"fontsize-18\"},{\"offset\":238,\"length\":5,\"style\":\"fontsize-18\"},{\"offset\":260,\"length\":2,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":270,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":3,\"length\":35,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":46,\"length\":31,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":84,\"length\":1,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":86,\"length\":2,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":99,\"length\":15,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":130,\"length\":16,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":151,\"length\":11,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":178,\"length\":11,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":190,\"length\":2,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":204,\"length\":26,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":238,\"length\":5,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":260,\"length\":2,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":39,\"length\":6,\"style\":\"CODE\"},{\"offset\":78,\"length\":6,\"style\":\"CODE\"},{\"offset\":89,\"length\":9,\"style\":\"CODE\"},{\"offset\":115,\"length\":14,\"style\":\"CODE\"},{\"offset\":147,\"length\":3,\"style\":\"CODE\"},{\"offset\":163,\"length\":14,\"style\":\"CODE\"},{\"offset\":193,\"length\":10,\"style\":\"CODE\"},{\"offset\":231,\"length\":7,\"style\":\"CODE\"},{\"offset\":244,\"length\":15,\"style\":\"CODE\"},{\"offset\":263,\"length\":7,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"1comd\",\"text\":\"6. Swap largest with currentElement\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":35,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":4,\"length\":3,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":16,\"length\":4,\"style\":\"bgcolor-rgb(249,250,252)\"},{\"offset\":4,\"length\":3,\"style\":\"fontsize-18\"},{\"offset\":16,\"length\":4,\"style\":\"fontsize-18\"},{\"offset\":8,\"length\":7,\"style\":\"CODE\"},{\"offset\":21,\"length\":14,\"style\":\"CODE\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"ah1kp\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":5}],\"data\":{}},{\"key\":\"bviqd\",\"text\":\"7. Repeat steps 3-7 until the subtrees are also heapified.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":58,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":58,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":58,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"margin-left\":\"0px\"}},{\"key\":\"79v0e\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"bmcfo\",\"text\":\"Insert element into heap\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":24,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":24,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":24,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"46urd\",\"text\":\"1. Insert the new element at the end of the tree.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":49,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":49,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":49,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"7g27p\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"jgab\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":6}],\"data\":{}},{\"key\":\"ar0db\",\"text\":\"2. Heapify the tree.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":20,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":20,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":20,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"9o876\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"fo8qb\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":7}],\"data\":{}},{\"key\":\"funrp\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"6gvm9\",\"text\":\"For Min Heap, the above algorithm is modified so that parentNode is always smaller than newNode\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":53,\"style\":\"fontsize-18\"},{\"offset\":65,\"length\":22,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":95,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":54,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":64,\"length\":24,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":95,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":54,\"length\":10,\"style\":\"bgcolor-rgb(239,239,239)\"},{\"offset\":88,\"length\":7,\"style\":\"bgcolor-rgb(239,239,239)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"b16l3\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"51pe9\",\"text\":\"Delete element from heap\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":24,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":24,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":24,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"cqdno\",\"text\":\"1. Select the element to be deleted.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":36,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":36,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":36,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":3,\"length\":33,\"style\":\"bgcolor-rgb(255,255,255)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"ef28k\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"e9qkr\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":8}],\"data\":{}},{\"key\":\"npf2\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"1r2mu\",\"text\":\"2. Swap it with the last element.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":33,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":33,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":33,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":33,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"3j91e\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"9ub0j\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":9}],\"data\":{}},{\"key\":\"7cuf8\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"dvhan\",\"text\":\"3. Remove the last element.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":27,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":27,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":27,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"35thp\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"d73dd\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":10}],\"data\":{}},{\"key\":\"6ohpi\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"6r4u3\",\"text\":\"4. Heapify the tree\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":19,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":19,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":19,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":19,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"4o81a\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"3d411\",\"text\":\" \",\"type\":\"atomic\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[{\"offset\":0,\"length\":1,\"key\":11}],\"data\":{}},{\"key\":\"6rq5i\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"c4ecq\",\"text\":\"For Min Heap, above algorithm is modified so that both childNodes are greater smaller than currentNode.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":54,\"style\":\"fontsize-18\"},{\"offset\":66,\"length\":24,\"style\":\"fontsize-18\"},{\"offset\":102,\"length\":1,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":54,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":66,\"length\":24,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":54,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":66,\"length\":24,\"style\":\"bgcolor-rgb(255,255,255)\"},{\"offset\":0,\"length\":103,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":55,\"length\":10,\"style\":\"CODE\"},{\"offset\":91,\"length\":11,\"style\":\"CODE\"},{\"offset\":102,\"length\":1,\"style\":\"color-rgba(37,38,94,0.7)\"},{\"offset\":102,\"length\":1,\"style\":\"bgcolor-rgb(249,250,252)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"4tekh\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"5easq\",\"text\":\"Peek (Find max/min)\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":19,\"style\":\"fontsize-20\"},{\"offset\":0,\"length\":19,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":19,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c77t4\",\"text\":\"Peek operation returns the maximum element from Max Heap or minimum element from Min Heap without deleting the node.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":116,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":116,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":116,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7800n\",\"text\":\"For both Max heap and Min Heap\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":30,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":30,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":30,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"a2u1u\",\"text\":\"return rootNode\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":15,\"style\":\"fontsize-14\"},{\"offset\":0,\"length\":15,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":15,\"style\":\"bgcolor-rgb(239,239,239)\"},{\"offset\":0,\"length\":15,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"8n1i\",\"text\":\"\\nExtract-Max/Min\",\"type\":\"header-three\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":16,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":1,\"length\":15,\"style\":\"fontsize-20\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"adqbp\",\"text\":\"Extract-Max returns the node with maximum value after removing it from a Max Heap whereas Extract-Min returns the node with minimum after removing it from Min Heap.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":164,\"style\":\"fontsize-medium\"},{\"offset\":0,\"length\":164,\"style\":\"fontsize-18\"},{\"offset\":0,\"length\":164,\"style\":\"fontfamily-Times New Roman\"},{\"offset\":163,\"length\":1,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":163,\"length\":1,\"style\":\"color-rgba(37,38,94,0.7)\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"at0c1\",\"text\":\"\\nAn implementation of a max heap in C++ is showed below:\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":56,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"6s9o0\",\"text\":\"// Max-Heap data structure in C++\\n\\n#include <iostream>\\n#include <vector>\\nusing namespace std;\\n\\nvoid swap(int *a, int *b)\\n{\\n  int temp = *b;\\n  *b = *a;\\n  *a = temp;\\n}\\nvoid heapify(vector<int> &hT, int i)\\n{\\n  int size = hT.size();\\n  int largest = i;\\n  int l = 2 * i + 1;\\n  int r = 2 * i + 2;\\n  if (l < size && hT[l] > hT[largest])\\n    largest = l;\\n  if (r < size && hT[r] > hT[largest])\\n    largest = r;\\n\\n  if (largest != i)\\n  {\\n    swap(&hT[i], &hT[largest]);\\n    heapify(hT, largest);\\n  }\\n}\\nvoid insert(vector<int> &hT, int newNum)\\n{\\n  int size = hT.size();\\n  if (size == 0)\\n  {\\n    hT.push_back(newNum);\\n  }\\n  else\\n  {\\n    hT.push_back(newNum);\\n    for (int i = size / 2 - 1; i >= 0; i--)\\n    {\\n      heapify(hT, i);\\n    }\\n  }\\n}\\nvoid deleteNode(vector<int> &hT, int num)\\n{\\n  int size = hT.size();\\n  int i;\\n  for (i = 0; i < size; i++)\\n  {\\n    if (num == hT[i])\\n      break;\\n  }\\n  swap(&hT[i], &hT[size - 1]);\\n\\n  hT.pop_back();\\n  for (int i = size / 2 - 1; i >= 0; i--)\\n  {\\n    heapify(hT, i);\\n  }\\n}\\nvoid printArray(vector<int> &hT)\\n{\\n  for (int i = 0; i < hT.size(); ++i)\\n    cout << hT[i] << \\\" \\\";\\n  cout << \\\"\\\\n\\\";\\n}\\n\\nint main()\\n{\\n  vector<int> heapTree;\\n\\n  insert(heapTree, 3);\\n  insert(heapTree, 4);\\n  insert(heapTree, 9);\\n  insert(heapTree, 5);\\n  insert(heapTree, 2);\\n\\n  cout << \\\"Max-Heap array: \\\";\\n  printArray(heapTree);\\n\\n  deleteNode(heapTree, 4);\\n\\n  cout << \\\"After deleting an element: \\\";\\n\\n  printArray(heapTree);\\n}\",\"type\":\"code\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":1422,\"style\":\"color-rgb(0,0,0)\"},{\"offset\":0,\"length\":1422,\"style\":\"fontfamily-Times New Roman\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"cnq8t\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"4p0cp\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{\"0\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/OTLuUbQZmYPjHkXgmCfzHr8nNCkoi2Je9y9ZzIl1vuI/mtime:1582112622/sites/tutorial2program/files/maxheap_1.png\",\"height\":\"100px\",\"width\":\"100px\"}},\"1\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/tVzREVaraXbOKPPJtMbcQ10N2QkxiAJcNOIfxPYlVR0/mtime:1582112622/sites/tutorial2program/files/minheap_0.png\",\"height\":\"100px\",\"width\":\"100px\"}},\"2\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/u7XieTY7hkqyS4EPPVoQdv_dz8yie8Kt23yrk2T0tI4/mtime:1582112622/sites/tutorial2program/files/array_1.png\",\"height\":\"150px\",\"width\":\"400px\"}},\"3\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/lnR3gOMRgb2thamLGxVMsWt91B0Wl7ffnwmoznqFr-U/mtime:1582112622/sites/tutorial2program/files/completebt-1_0.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"4\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/Yu605X8Aw6w-sPRAT8jcauJYO14Tz5_INL8804qwrMc/mtime:1582112622/sites/tutorial2program/files/start_1.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"5\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/rne2vKIuPdxESHiHCx9QkOJptBH4erly6Rz16BESGcs/mtime:1582112622/sites/tutorial2program/files/swap_1.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"6\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/Vh5M3W_PuMk0BtajkiY6aAbAbIq9QXwuIbtKlatIGN8/mtime:1588229923/sites/tutorial2program/files/insert-heap-1.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"7\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/J6CSUS2XozRVvpUomcF8wANPpVViFh6X-ARbCdqzB_0/mtime:1588229931/sites/tutorial2program/files/insert-heap-2.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"8\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/jWHmWXLJa2YGlGWeEHNukIScbz5rjuzBgEqAq0YrVeg/mtime:1582112622/sites/tutorial2program/files/delete-1_1.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"9\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/BvW8pJo3K9yK7dzRmSoA8YVkeDPRCIdBJIEskW2KTL0/mtime:1582112622/sites/tutorial2program/files/delete-2_1.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"10\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/SwbN81J6KRUxyFrWIrAHFTe3kd7fUIvcYmH9Sg9SQzo/mtime:1582112622/sites/tutorial2program/files/delete-3_0.png\",\"height\":\"150px\",\"width\":\"150px\"}},\"11\":{\"type\":\"IMAGE\",\"mutability\":\"MUTABLE\",\"data\":{\"src\":\"https://cdn.programiz.com/cdn/farfuture/9o8W0NbKEGKcaxuNb7hqWB16e_Iyw-7Hp8uh08GrHAc/mtime:1582112622/sites/tutorial2program/files/delete-4_0.png\",\"height\":\"150px\",\"width\":\"150px\"}}}}','2022-05-30 22:12:21',1,1);

INSERT INTO `SOFT_SKILL_TOPIC` (`id`, `title`, `description`, `topic_information`, `created_date`, `is_active`, `created_by`)
VALUES
	('this is a title','this is a descritpion','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"this is a \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"bjcu7\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"7htl9\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"9us8u\",\"text\":\"test for a soft skill\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":4,\"style\":\"fontfamily-Impact\"},{\"offset\":11,\"length\":4,\"style\":\"SUBSCRIPT\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"4vr55\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{\"text-align\":\"center\"}},{\"key\":\"9eifa\",\"text\":\"topic \",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"3uvss\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"dlpdg\",\"text\":\"test 222222\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":5,\"length\":6,\"style\":\"SUPERSCRIPT\"}],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-07 21:03:50',1,1),
	('Soft Skills?','A deeper understanding of soft skills','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"Why?\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":4,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c0h2e\",\"text\":\"Simply hiring the most experienced candidate may seem like the most logical and sensible decision; but there’s a lot more to what makes a good team member than qualifications and experience. Understanding the difference between soft and hard skills, and why soft skills are absolutely essential is vital in establishing a stronger, more efficient team.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":352,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":352,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":352,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"c0om3\",\"text\":\"As business continues to evolve at a rapid pace, and the traditional concept of the \'career\' shifts and reshapes, having transferrable skills that can be applied in any position and any industry is only becoming more important every day.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":237,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":237,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":237,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2e3ul\",\"text\":\"While for a long while, hard skills were considered the more \'professional skills\' and soft skills were viewed only as a CV space-filler, studies have shown that these days, human resources professionals tend to favour soft skills over hard skills when choosing the ideal candidate.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":282,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":282,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":282,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":138,\"length\":18,\"style\":\"color-inherit\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"9ht9g\",\"text\":\"Hard skills are measurable, tangible proficiencies that, while important in any position, are not the ultimate determinant of what makes a good employee. Hard skills refer to technical ability, like mathematics, reading comprehension, language fluency and computer skills, to name a few.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":287,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":287,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":287,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"s1jn\",\"text\":\"Soft skills, on the other hand, are personality traits and characteristics that are less quantifiable, but equally as important in the workplace and beyond, if not more. They’re rooted in behaviour, attitude and values.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":219,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":219,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":219,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"3s4j3\",\"text\":\"While hard skills have a larger impact on the work you produce, soft skills help develop human connections and establish a sense of culture and community in the workplace. Having said that, soft skills absolutely have a positive impact on the work you produce, especially when working collaboratively.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":301,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":301,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":301,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"f8pn1\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"eo2i6\",\"text\":\"What are the most important soft skills?\",\"type\":\"header-two\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":40,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":40,\"style\":\"fontsize-40\"},{\"offset\":0,\"length\":40,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":0,\"length\":40,\"style\":\"BOLD\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"426gm\",\"text\":\"1. Emotional intelligence\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":25,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":25,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":25,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"82h90\",\"text\":\"2. Communication\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":16,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":16,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":16,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7vrp3\",\"text\":\"3. Teamwork & respect\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":21,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":21,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":21,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c32u\",\"text\":\"4. Flexibility & creativity\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":27,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":27,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"7h4rc\",\"text\":\"5. Problem-solving & critical thinking\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":38,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":38,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":38,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"62rl6\",\"text\":\"6. Leadership\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":13,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":13,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":13,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"med3\",\"text\":\"7. Time management & organisation\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":33,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":33,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":33,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"3592g\",\"text\":\"8. Motivation & work ethic\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":26,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":26,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":26,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"bnb2s\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"ef1o\",\"text\":\"Each one of these soft skills will be discussed more in depth in further activities.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":84,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":84,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":84,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{}},{\"key\":\"2mbgu\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"31d81\",\"text\":\"\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}}],\"entityMap\":{}}','2022-05-31 22:51:41',1,1),
	('Emotional intelligence and communication','These are two essential soft skills ','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"1. Emotional intelligence\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":25,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":25,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":25,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"1fdkk\",\"text\":\"Emotional intelligence encapsulates many of the vital characteristics of soft skills, from conflict resolution, to social skills, to self-awareness, to compassion and empathy.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":175,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":175,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":175,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":0,\"length\":22,\"style\":\"color-inherit\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"dbqbc\",\"text\":\"A person with high emotional intelligence has the ability to interpret, comprehend and manage the emotions of both themselves and those they work with. They can handle and manage pressure while helping others feel at ease, and they understand how their behaviour can impact their work environment. This ability to build strong interpersonal relationships is a soft skill that can bolster the productivity and performance of your team.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":434,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":434,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":434,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"f0916\",\"text\":\"A large part of emotional intelligence is also having excellent listening skills. Active listening inspires more open, productive communication in the workplace and ensures that everyone in the team feels recognised, understood and valued.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":239,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":239,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":239,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"5bcfk\",\"text\":\"2. Communication\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":16,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":16,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":16,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"fh562\",\"text\":\"Communication skills are crucial in the workplace, not just to help establish an open and welcoming environment, but to ensure that the work you produce is focused and clear.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":174,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":174,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":174,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"bsd11\",\"text\":\"A team that knows how to communicate well will be more efficient, more organised, and more in-tune with each other’s ideas and perspectives. Having communication skills doesn’t just mean having the gift of the gab; it goes far beyond verbal communication. The ability to easily communicate complex ideas and convey important messages with clarity and brevity, whether spoken, written or otherwise, will minimise mistakes and inefficiency.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":438,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":438,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":438,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"c40n1\",\"text\":\"Good collaborative work is simply not possible without efficient communication. It’s especially important as remote, digital working environments become more and more prevalent; strong soft skills help bring people together even when they’re working from afar. Tools like Dropbox are designed to facilitate and improve collaboration and communication, but ensuring that those using the tools have the soft skills to match is key.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":429,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":429,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":429,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":5,\"length\":18,\"style\":\"color-inherit\"},{\"offset\":296,\"length\":36,\"style\":\"color-inherit\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}}],\"entityMap\":{}}','2022-05-31 22:56:55',1,1),
	('Teamwork and flexibility','What is benefitial of these skills?','{\"blocks\":[{\"key\":\"ap25h\",\"text\":\"3. Teamwork & respect\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":21,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":21,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":21,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"d788o\",\"text\":\"Being a good team player means going above and beyond to reach the collective goals of the team. It means putting selfishness aside and truly caring for those you collaborate with, taking whatever steps necessary to ensure the team operates with fluidity and cohesion, and putting the best interests of the team above your own. Team players are open and honest with one another, they exhibit dependability and loyalty in every way.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":431,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":431,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":431,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"4d2va\",\"text\":\"Mutual respect between you and your coworkers is absolutely vital. That means respecting different views and opinions, respecting each person’s responsibilities, and respecting the work that you do. A workplace without respect simply cannot produce respectable work.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":266,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":266,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":266,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"ah7lu\",\"text\":\"4. Flexibility & creativity\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":27,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":27,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":27,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"65bd0\",\"text\":\"The ability to adapt to new environments and challenges is a hugely valuable trait. No matter what the job, company or industry, we should always expect the unexpected, and have the flexibility to adapt to whatever comes our way. Whether it’s adapting to new technology, new systems and structures or simply a new project, versatility is crucial towards any team’s success.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":373,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":373,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":373,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"9sggo\",\"text\":\"Creativity is equally important in an ever-evolving business environment; having the ability to think outside the box and strategise innovative concepts and ideas makes you a reliable, valuable member of any team. Some problems require fresh solutions, and creativity is what drives innovation and progress. A team of creative thinkers is a team that is well equipped for growth and development.\\n\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":395,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":395,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":395,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}}],\"entityMap\":{}}','2022-05-31 22:58:09',1,1),
	('Problem solving and leadership','Problem solving skills and being able to lead','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"5. Problem-solving & critical thinking\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":38,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":38,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":38,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"e93vv\",\"text\":\"Coming hand-in-hand with flexibility and creativity, problem solving skills are the ability to deconstruct issues and take immediate, logical actions to solve them. Knowing that your team is ready and able to strategise productive, rational solutions to unexpected problems will heighten and inspire confidence in the workplace and help you tackle challenging obstacles without stress or burden.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":395,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":395,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":395,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"fflsu\",\"text\":\"The ability to look deeper at an issue and analyse and evaluate its nuances with a logical, systematic approach will ensure that you always arrive at the strongest solution possible. Critical thinking means completely deconstructing every angle of the issue and avoiding decision making that’s based on instinct or intuition.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":325,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":325,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":325,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"claaf\",\"text\":\"\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[],\"entityRanges\":[],\"data\":{}},{\"key\":\"4gt84\",\"text\":\"6. Leadership\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":13,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":13,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":13,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"25ut\",\"text\":\"Regardless of their specific job title or position within the company hierarchy, leadership skills are absolutely essential in any role. You want your team to be motivated, driven and goal-orientated, and you want to facilitate growth and development. Ensuring each individual in your team has strong leadership skills gives you reassurance that you can rely on anybody to take control.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":386,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":386,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":386,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"sj5n\",\"text\":\"When you bring a member into your team, you want to be able to see them in your long-term business plans. You want a team that is willing and ready to grow, and that has the space and tools to do so.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":199,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":199,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":199,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"d5a6t\",\"text\":\"A good leader does not simply make commands, they inspire and encourage their team, and they care about those who work with and for them. Leadership is not reserved for bosses, managers and supervisors, and a person with leadership skills has the ability to take ownership and authority over even the smallest of projects or tasks.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":331,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":331,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":331,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}}],\"entityMap\":{}}','2022-05-31 23:00:35',1,1),
	('Time management and motivation','Being able to motivate yourself and do it on time is beneficial in all aspects','{\"blocks\":[{\"key\":\"637gr\",\"text\":\"7. Time management & organisation\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":33,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":33,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":33,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"bofej\",\"text\":\"Knowing you can trust your team to get the job done promptly, without compromising the quality of the work, is hugely important. Time management is more than just showing up on time and delivering work when it’s asked for, it’s about knowing how to prioritise, how to schedule and how to make the very most of the time you’ve got. Time management doesn’t just improve productivity and efficiency, it will also have a positive impact on the quality of the work you produce.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":276,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":277,\"length\":195,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":276,\"style\":\"fontsize-16\"},{\"offset\":277,\"length\":195,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":276,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":277,\"length\":195,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"},{\"offset\":129,\"length\":15,\"style\":\"color-inherit\"},{\"offset\":261,\"length\":15,\"style\":\"color-inherit\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"4uimr\",\"text\":\"Clutter is never good for any working environment, whether it be in the office, digitally or in your mind. Being organised means knowing how to efficiently manage not only the space you work in, but also your time and workload. Someone who is truly organised will have the ability to create and adhere to systems and structures that aid efficiency, and will not allow themselves to become overwhelmed or their processes to become messy.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":436,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":436,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":436,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"f54ao\",\"text\":\"8. Motivation & work ethic\",\"type\":\"header-four\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":26,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":26,\"style\":\"fontsize-25\"},{\"offset\":0,\"length\":26,\"style\":\"fontfamily-SharpGrotesk23, SharpGrotesk23KR, SharpGrotesk23Thai, AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"dmqoe\",\"text\":\"You want to know that you’re getting the best work possible out of you and your co-workers, and one way to do so is to understand, encourage and leverage the motivations of those you work with.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":193,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":193,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":193,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"2j8ko\",\"text\":\"A highly skilled coder, for example, may seem valuable, but their true potential won’t reflect on the work they do unless they’re driven to do their best.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":154,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":154,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":154,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"4e46t\",\"text\":\"Motivation can and should be influenced by both personal and professional achievement. You need to know that your team truly cares about what they are doing. If they’re not passionate about the work, and if they’re not dedicated to the wider goals of the team and organisation, they will not do their best work.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":311,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":311,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":311,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}},{\"key\":\"b19c9\",\"text\":\"Work ethic is very similar to motivation. A person with good work ethic enjoys what they do, they understand and accept their responsibilities. They’re disciplined, focused and always professional. Strong work ethic and motivation means understanding that hard work pays off and putting the upmost effort into every aspect of the job.\",\"type\":\"unstyled\",\"depth\":0,\"inlineStyleRanges\":[{\"offset\":0,\"length\":334,\"style\":\"color-rgb(30,25,25)\"},{\"offset\":0,\"length\":334,\"style\":\"fontsize-16\"},{\"offset\":0,\"length\":334,\"style\":\"fontfamily-AtlasGrotesk, \\\"Open Sans\\\", sans-serif\"}],\"entityRanges\":[],\"data\":{\"text-align\":\"start\"}}],\"entityMap\":{}}','2022-05-31 23:02:18',1,1);

